settings.custom_css:
selector {
    /* 🧊 Glass effect */
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    background: rgba(255, 255, 255, 0.15);

    /* ❌ No border */
    border: none;

    /* ✂ Corner cuts (top-right & bottom-left) */
    clip-path: polygon(
        0% 0px,
        0px 0%,
        calc(100% - 50px) 0px,
        100% 50px,
        100% 100%,
        calc(100% - 0px) 100%,
        50px 100%,
        0px calc(100% - 50px)
    );
}

